Javascript.validate:
var value = Services.getValue(MonthlyInstalment.dataBinding);	      
   var maxVal = 999999.99;
   var err = validateCurrencyValue(value, maxVal);
   if( err == null)
   { 	         
    Services.setValue(MonthlyInstalment.dataBinding, WPU.formatToTwoDP(value));		   
 }
 return err;

Javascript.miscCode:
function DefaultCurrency85() {}
DefaultCurrency85.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency85.tabIndex = -1;
DefaultCurrency85.maxLength = 1;
DefaultCurrency85.isReadOnly = function(){return true;}
DefaultCurrency85.isTemporary = function(){return true;}
DefaultCurrency85.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency85.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
